sql:
SELECT behavior_type 
FROM squirrel_behavior 
WHERE behavior_id = 0;

SELECT COUNT(characteristic_id) AS count_long_fluffy_tails
FROM squirrel_characteristics
WHERE characteristic_description = 'Squirrel had a long and fluffy tail';

SELECT COUNT(*) AS sighting_count
FROM squirrel_sightings_history
WHERE researcher_id = 1;

SELECT MIN(sighting_date) AS earliest_sighting, sighting_notes
FROM squirrel_sightings_history
WHERE sighting_date IS NOT NULL;

SELECT MIN(sighting_date) AS EarliestSightingDate, researcher_id
FROM squirrel_sightings_history
GROUP BY researcher_id;

SELECT DISTINCT sighting_date
FROM squirrel_sightings_history
ORDER BY sighting_date;

SELECT behavior_type, behavior_description, COUNT(*) as observation_count
FROM squirrel_behavior
GROUP BY behavior_type, behavior_description;

SELECT habitat_type, habitat_description
FROM squirrel_habitat
WHERE habitat_type = 'Forest';

SELECT sighting_id, behavior_type
FROM squirrel_behavior
WHERE behavior_type = 'Foraging';

SELECT sighting_date, researcher_id
FROM squirrel_sightings_history
ORDER BY sighting_date DESC;
